@WebService(serviceName = "OrderProcessingService", targetNamespace = "http://ecommerce.b2b.com/")
@SOAPBinding(style = Style.DOCUMENT)
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(@WebParam(name = "orderRequest") OrderRequest orderRequest) {
        try {
            if (orderRequest == null) {
                return new OrderResponse(null, "FAILED", "Order request is null", BigDecimal.ZERO, new Date(), null);
            }

            if (orderRequest.getOrderItems() == null || orderRequest.getOrderItems().isEmpty()) {
                return new OrderResponse(null, "FAILED", "No order items provided", BigDecimal.ZERO, new Date(), null);
            }

            if (orderRequest.getCustomerId() == null || orderRequest.getCustomerId().trim().isEmpty()) {
                return new OrderResponse(null, "FAILED", "Customer ID is required", BigDecimal.ZERO, new Date(), null);
            }

            BigDecimal totalAmount = calculateTotalPrice(orderRequest.getOrderItems());

            if (totalAmount.compareTo(BigDecimal.ZERO) <= 0) {
                return new OrderResponse(null, "FAILED", "Invalid order total", totalAmount, new Date(), null);
            }

            String orderId = generateOrderId();
            Date orderDate = new Date();
            String estimatedDeliveryDate = calculateEstimatedDeliveryDate();

            boolean processed = processOrderInDatabase(orderId, orderRequest, totalAmount, orderDate);

            if (processed) {
                return new OrderResponse(
                    orderId,
                    "SUCCESS",
                    "Order processed successfully",
                    totalAmount,
                    orderDate,
                    estimatedDeliveryDate
                );
            } else {
                return new OrderResponse(
                    null,
                    "FAILED",
                    "Failed to process order",
                    totalAmount,
                    orderDate,
                    null
                );
            }

        } catch (Exception e) {
            return new OrderResponse(
                null,
                "ERROR",
                "Error processing order: " + e.getMessage(),
                BigDecimal.ZERO,
                new Date(),
                null
            );
        }
    }

    @WebMethod(operationName = "getOrderStatus")
    public OrderStatusResponse getOrderStatus(@WebParam(name = "orderId") String orderId) {
        try {
            if (orderId == null || orderId.trim().isEmpty()) {
                return new OrderStatusResponse(null, "ERROR", BigDecimal.ZERO, null);
            }

            OrderStatusResponse status = retrieveOrderStatus(orderId);
            
            if (status != null) {
                return status;
            } else {
                return new OrderStatusResponse(orderId, "NOT_FOUND", BigDecimal.ZERO, null);
            }

        } catch (Exception e) {
            return new OrderStatusResponse(orderId, "ERROR", BigDecimal.ZERO, null);
        }
    }

    @WebMethod(operationName = "cancelOrder")
    public OrderResponse cancelOrder(@WebParam(name = "orderId") String orderId, 
                                     @WebParam(name = "customerId") String customerId) {
        try {
            if (orderId == null || orderId.trim().isEmpty()) {
                return new OrderResponse(null, "FAILED", "Order ID is required", BigDecimal.ZERO, new Date(), null);
            }

            if (customerId == null || customerId.trim().isEmpty()) {
                return new OrderResponse(null, "FAILED", "Customer ID is required", BigDecimal.ZERO, new Date(), null);
            }

            boolean cancelled = cancelOrderInDatabase(orderId, customerId);

            if (cancelled) {
                return new OrderResponse(
                    orderId,
                    "CANCELLED",
                    "Order cancelled successfully",
                    BigDecimal.ZERO,
                    new Date(),
                    null
                );
            } else {
                return new OrderResponse(
                    orderId,
                    "FAILED",
                    "Failed to cancel order or order not found",
                    BigDecimal.ZERO,
                    new Date(),
                    null
                );
            }

        } catch (Exception e) {
            return new OrderResponse(
                orderId,
                "ERROR",
                "Error cancelling order: " + e.getMessage(),
                BigDecimal.ZERO,
                new Date(),
                null
            );
        }
    }

    @WebMethod(operationName = "calculateOrderTotal")
    public BigDecimal calculateOrderTotal(@WebParam(name = "orderItems") List<OrderItem> orderItems) {
        try {
            if (orderItems == null || orderItems.isEmpty()) {
                return BigDecimal.ZERO;
            }
            return calculateTotalPrice(orderItems);
        } catch (Exception e) {
            return BigDecimal.ZERO;
        }
    }

    private BigDecimal calculateTotalPrice(List<OrderItem> orderItems) {
        BigDecimal total = BigDecimal.ZERO;
        
        for (OrderItem item : orderItems) {
            if (item.getUnitPrice() != null && item.getQuantity() > 0) {
                BigDecimal lineTotal = item.getUnitPrice()
                    .multiply(new BigDecimal(item.getQuantity()))
                    .setScale(2, RoundingMode.HALF_UP);
                total = total.add(lineTotal);
            }
        }
        
        return total.setScale(2, RoundingMode.HALF_UP);
    }

    private String generateOrderId() {
        return "ORD-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
    }

    private String calculateEstimatedDeliveryDate() {
        long currentTime = System.currentTimeMillis();
        long deliveryTime = currentTime + (7L * 24 * 60 * 60 * 1000);
        return new Date(deliveryTime).toString();
    }

    private boolean processOrderInDatabase(String orderId, OrderRequest orderRequest, 
                                          BigDecimal totalAmount, Date orderDate) {
        System.out.println("Processing order: " + orderId);
        System.out.println("Customer: " + orderRequest.getCustomerName() + " (" + orderRequest.getCustomerId() + ")");
        System.out.println("Total Amount: $" + totalAmount);
        System.out.println("Order Date: " + orderDate);
        System.out.println("Items:");
        
        for (OrderItem item : orderRequest.getOrderItems()) {
            System.out.println("  - " + item.getItemName() + 
                             " (ID: " + item.getItemId() + 
                             ") x " + item.getQuantity() + 
                             " @ $" + item.getUnitPrice() + 
                             " = $" + item.getLineTotal());
        }
        
        return true;
    }

    private OrderStatusResponse retrieveOrderStatus(String orderId) {
        return new OrderStatusResponse(
            orderId,
            "PROCESSING",
            new BigDecimal("1250.00"),
            new Date()
        );
    }

    private boolean cancelOrderInDatabase(String orderId, String customerId) {
        System.out.println("Cancelling order: " + orderId + " for customer: " + customerId);
        return true;
    }
}